const mem = {};
const store = {
  async get(k, s = true) { try { if (window.storage) return await window.storage.get(k, s); } catch (e) {} return k in mem ? { key: k, value: mem[k] } : null; },
  async set(k, v, s = true) { try { if (window.storage) return await window.storage.set(k, v, s); } catch (e) {} mem[k] = v; return { key: k, value: v }; },
  async list(p, s = true) { try { if (window.storage) return await window.storage.list(p, s); } catch (e) {} return { keys: Object.keys(mem).filter((x) => x.startsWith(p)) }; },
};

