function useCountUp(target, run, dur = 1100) {
  const [v, setV] = useState(0);
  useEffect(() => { if (!run) return; let raf, t0; const tick = (t) => { if (!t0) t0 = t; const p = Math.min((t - t0) / dur, 1); setV(target * (1 - Math.pow(1 - p, 3))); if (p < 1) raf = requestAnimationFrame(tick); }; raf = requestAnimationFrame(tick); return () => cancelAnimationFrame(raf); }, [target, run]);
  return v;
}

