function Btn({ children, onClick, kind = "primary", disabled, full }) {
  const base = { primary: { background: C.rose, color: "#fff", border: "none" }, ghost: { background: "#fff", color: C.roseDeep, border: `1.5px solid ${C.line}` }, teal: { background: C.teal, color: "#fff", border: "none" } }[kind];
  return <button onClick={onClick} disabled={disabled} className="chunky btnA" style={{ ...base, opacity: disabled ? 0.4 : 1, cursor: disabled ? "default" : "pointer", width: full ? "100%" : "auto", padding: "13px 24px", borderRadius: 12, fontFamily: sans, fontSize: 15.5, fontWeight: 600, boxShadow: disabled ? "none" : "0 2px 7px rgba(35,33,54,.10)", display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 8 }}>{children}</button>;
}
const Card = ({ children, style, className }) => <div className={className} style={{ background: C.surface, borderRadius: 18, padding: 20, boxShadow: "0 2px 14px rgba(35,33,54,.06)", ...style }}>{children}</div>;
const Eyebrow = ({ children }) => <div style={{ fontFamily: sans, fontSize: 12, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", color: C.rose, marginBottom: 10 }}>{children}</div>;
const H = ({ children, style }) => <h1 style={{ fontFamily: serif, fontWeight: 700, fontSize: 27, lineHeight: 1.2, color: C.ink, margin: "0 0 12px", ...style }}>{children}</h1>;
const P = ({ children, style }) => <p style={{ fontFamily: sans, fontSize: 16, lineHeight: 1.65, color: C.ink, margin: "0 0 14px", ...style }}>{children}</p>;

