            {title && <h1 style={{ fontFamily: serif, fontWeight: 700, fontSize: 28, lineHeight: 1.12, color: onImg ? "#fff" : C.ink, margin: 0, textShadow: onImg ? "0 1px 14px rgba(0,0,0,.32)" : "none" }}>{title}</h1>}
