function Coin({ sym, metal, label, Icon, rot, size, delay, onPick }) {
  const [clk, setClk] = useState(false);
  const metals = { gold: ["#F8D873", "#E2AE40", "#A9781C"], copper: ["#EDB07A", "#CD7E3E", "#8E5223"], silver: ["#EFF1F4", "#CBCDD3", "#969AA3"] };
  const [hi, mid, lo] = metals[metal] || metals.gold;
  const fs = sym.length > 1 ? size * 0.3 : size * 0.42;
  const face = { position: "absolute", inset: 0, backfaceVisibility: "hidden", WebkitBackfaceVisibility: "hidden", borderRadius: "50%", border: `3px solid ${lo}`, display: "flex", alignItems: "center", justifyContent: "center", background: `radial-gradient(circle at 36% 30%, ${hi}, ${mid} 58%, ${lo})`, boxShadow: "inset 0 3px 7px rgba(255,255,255,.55), inset 0 -5px 9px rgba(0,0,0,.18)" };
  const pick = () => { setClk(true); setTimeout(onPick, 560); };
  return (
    <div className="coinWrap" onClick={pick} role="button" aria-label={label} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 9, width: size + 18, cursor: "pointer", transform: `rotate(${rot}deg)` }}>
      <div style={{ width: size, height: size, perspective: 620, animation: `floatY ${3 + (delay % 3)}s ease-in-out ${delay * 0.18}s infinite` }}>
        <div className="coin3d" style={{ position: "relative", width: "100%", height: "100%", transformStyle: "preserve-3d", filter: "drop-shadow(0 7px 8px rgba(27,26,58,.3))", animation: clk ? "coinSpin .56s linear" : "none" }}>
          <div style={face}><span style={{ fontFamily: serif, fontWeight: 700, fontSize: fs, color: "#5C3F12", textShadow: "0 1px 0 rgba(255,255,255,.45)" }}>{sym}</span></div>
          <div style={{ ...face, transform: "rotateY(180deg)" }}><Icon size={size * 0.4} color="#5C3F12" /></div>
        </div>
      </div>
      <div style={{ fontFamily: sans, fontSize: 11.5, fontWeight: 800, color: VIB.navy, textAlign: "center", lineHeight: 1.12, textTransform: "uppercase", letterSpacing: 0.3, transform: `rotate(${-rot}deg)` }}>{label}</div>
    </div>
  );
}
