/* ---------------- QUIZ ---------------- */
function Quiz({ cx, save, back, go }) {
  const total = QUIZ.feelings.length + QUIZ.knowledge.length;
  const [step, setStep] = useState(0);
  const [feel, setFeel] = useState({});
  const [ans, setAns] = useState({});
  const isFeel = step < QUIZ.feelings.length;
  const ki = step - QUIZ.feelings.length;
  const done = step >= total;
  const next = () => setStep((s) => s + 1);
  useEffect(() => { if (done) { const score = QUIZ.knowledge.reduce((a, q, i) => a + (ans[i] === q.c ? 1 : 0), 0); if (!cx.baseline) save({ baseline: { forMe: feel.forMe, conf: feel.conf, knowledge: score } }); else save({ endline: { forMe: feel.forMe, conf: feel.conf }, retakeKnowledge: score }); } }, [done]); // eslint-disable-line

  if (done) {
    const score = QUIZ.knowledge.reduce((a, q, i) => a + (ans[i] === q.c ? 1 : 0), 0);
    const level = score <= 2 ? "Just starting out" : score <= 4 ? "Finding your feet" : "Quietly capable";
    const msg = score <= 2 ? "Perfect place to be. Everyone starts here, and small steps move fast." : score <= 4 ? "You know more than you give yourself credit for. Let's fill the gaps." : "You've got real footing. Now it's about momentum, and maybe helping others.";
    const recs = score <= 2 ? [["guides", "Read the plain-English guides"], ["normal", "See: you're not behind"], ["forum", "Meet the community"]] : score <= 4 ? [["guides", "Guides on pensions & investing"], ["templates", "Grab a budget template"], ["forum", "Join the forum"]] : [["forum", "Help others in the forum"], ["media", "Go deeper with trusted resources"], ["templates", "Grab the templates"]];
    return (
      <Shell screen="quizdone" back={back}>
        <div style={{ paddingTop: 10, textAlign: "center" }}>
          <div style={{ width: 60, height: 60, borderRadius: 999, background: C.tealSoft, display: "inline-flex", alignItems: "center", justifyContent: "center", marginBottom: 14, animation: "pop .6s ease both" }}><Sparkles size={26} color={C.teal} /></div>
          <Eyebrow>Your result</Eyebrow><H style={{ fontSize: 30 }}>{level}</H>
          <div style={{ fontFamily: serif, fontSize: 18, color: C.rose, marginBottom: 10 }}>{score} of {QUIZ.knowledge.length} on the basics</div>
          <P style={{ color: C.muted, maxWidth: 440, margin: "0 auto 22px" }}>{msg}</P>
        </div>
        <div style={{ fontFamily: serif, fontSize: 18, color: C.ink, marginBottom: 12 }}>We'd start you here</div>
        <div style={{ display: "grid", gap: 10 }}>
          {recs.map(([to, label]) => (<button key={to} onClick={() => go(to)} className="hub" style={{ display: "flex", alignItems: "center", justifyContent: "space-between", textAlign: "left", background: C.surface, boxShadow: "0 2px 12px rgba(35,33,54,.06)", borderRadius: 14, padding: "15px 16px", cursor: "pointer", fontFamily: sans, fontSize: 15.5, color: C.ink, fontWeight: 600 }}>{label}<ChevronRight size={18} color={C.muted} /></button>))}
        </div>
        <div style={{ marginTop: 18 }}><Btn kind="ghost" onClick={back} full>Back to home</Btn></div>
      </Shell>
    );
  }
  return (
    <Shell screen={"q" + step} back={back}>
      <div style={{ paddingTop: 6 }}>
        <div style={{ height: 6, borderRadius: 999, background: C.line, overflow: "hidden", marginBottom: 22 }}><div style={{ height: "100%", width: `${(step / total) * 100}%`, background: `linear-gradient(90deg,${C.rose},${C.teal})`, transition: "width .4s ease" }} /></div>
        {isFeel ? (() => { const f = QUIZ.feelings[step]; return (
          <Card style={{ animation: "fadeUp .4s ease both" }}><div style={{ fontSize: 13, color: C.muted, marginBottom: 8 }}>Warm-up · no wrong answers</div><div style={{ fontFamily: serif, fontSize: 20, color: C.ink, marginBottom: 16 }}>{f.q}</div><Scale value={feel[f.key]} onChange={(v) => { setFeel((p) => ({ ...p, [f.key]: v })); setTimeout(next, 240); }} low={f.low} high={f.high} /></Card>
        ); })() : (() => { const q = QUIZ.knowledge[ki]; return (
          <Card style={{ animation: "fadeUp .4s ease both" }}><div style={{ fontSize: 13, color: C.muted, marginBottom: 8 }}>Question {ki + 1} of {QUIZ.knowledge.length}</div><div style={{ fontFamily: serif, fontSize: 20, color: C.ink, marginBottom: 16 }}>{q.q}</div>
            <div style={{ display: "grid", gap: 9 }}>{q.a.map((opt, oi) => (<button key={oi} onClick={() => { setAns((p) => ({ ...p, [ki]: oi })); setTimeout(next, 200); }} className="scaleBtn" style={{ textAlign: "left", padding: "14px 15px", borderRadius: 12, cursor: "pointer", fontFamily: sans, fontSize: 15, border: ans[ki] === oi ? `2px solid ${C.rose}` : `1.5px solid ${C.line}`, background: ans[ki] === oi ? C.roseSoft : "#fff", color: C.ink }}>{opt}</button>))}</div>
          </Card>
        ); })()}
      </div>
    </Shell>
  );
}

