function FloatingPenny({ cx, save }) {
  const [open, setOpen] = useState(false);
  const [nudge, setNudge] = useState(false);
  const [msgs, setMsgs] = useState([{ role: "assistant", content: "Hi, I'm Penny. Ask me anything about money, no question is too small. What's on your mind?" }]);
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const endRef = useRef(null);
  useEffect(() => { const t = setTimeout(() => setNudge(true), 2600); const t2 = setTimeout(() => setNudge(false), 9000); return () => { clearTimeout(t); clearTimeout(t2); }; }, []);
  useEffect(() => { if (endRef.current) endRef.current.scrollIntoView({ behavior: "smooth" }); }, [msgs, busy, open]);
  const send = async (text) => {
    const t = (text || input).trim(); if (!t || busy) return;
    const nextMsgs = [...msgs, { role: "user", content: t }]; setMsgs(nextMsgs); setInput(""); setBusy(true);
    save({ pennyMsgs: (cx.pennyMsgs || 0) + 1 });
    try {
      const api = nextMsgs.filter((m, i) => !(i === 0 && m.role === "assistant")).map((m) => ({ role: m.role, content: m.content }));
      const res = await fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: 1000, system: PENNY_SYS, messages: api }) });
      const data = await res.json();
      const reply = (data.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n").trim();
      setMsgs((m) => [...m, { role: "assistant", content: reply || "I'm here, but I lost my thread for a second. Could you ask that again?" }]);
    } catch (e) { setMsgs((m) => [...m, { role: "assistant", content: "I can't reach my brain right now. Try again in a moment, or peek at the guides while you wait." }]); }
    finally { setBusy(false); }
  };
  const chips = ["How do I start investing with €50?", "What's an emergency fund?", "I feel behind. Am I?"];
  return (
    <>
      <style>{STYLE}</style>
      {!open && (
        <div style={{ position: "fixed", right: 18, bottom: 18, zIndex: 50, display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 8 }}>
          {nudge && <div style={{ background: "#fff", border: `1px solid ${C.line}`, borderRadius: 14, borderBottomRightRadius: 4, padding: "10px 13px", fontFamily: sans, fontSize: 13.5, color: C.ink, maxWidth: 200, boxShadow: "0 8px 24px rgba(42,36,56,.14)", animation: "fadeUp .4s ease both" }}>Hi, I'm Penny. Stuck on anything money? Ask me.</div>}
          <button onClick={() => { setOpen(true); setNudge(false); }} aria-label="Chat with Penny" className="btnA" style={{ width: 64, height: 64, borderRadius: 999, background: "#fff", border: "3px solid #fff", boxShadow: "0 8px 24px rgba(35,33,54,.30)", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", padding: 0, overflow: "hidden", animation: "floatY 3.5s ease-in-out infinite" }}>
            <PennyFace size={58} />
          </button>
        </div>
      )}
      {open && (
        <div style={{ position: "fixed", right: 16, bottom: 16, zIndex: 50, width: "min(370px, calc(100vw - 24px))", height: "min(560px, calc(100vh - 80px))", background: C.paper, border: `1px solid ${C.line}`, borderRadius: 20, boxShadow: "0 16px 50px rgba(42,36,56,.28)", display: "flex", flexDirection: "column", overflow: "hidden", animation: "fadeUp .3s ease both" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "13px 14px", background: C.surface, borderBottom: `1px solid ${C.line}` }}>
            <PennyFace size={38} />
            <div style={{ flex: 1 }}><div style={{ fontFamily: serif, fontSize: 17, color: C.ink }}>Penny</div><div style={{ fontSize: 11.5, color: C.muted }}>Friendly money companion</div></div>
            <button onClick={() => setOpen(false)} aria-label="Close" style={{ background: "none", border: "none", cursor: "pointer", color: C.muted, padding: 4 }}><X size={20} /></button>
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: 14, display: "grid", gap: 10, alignContent: "start" }}>
            {msgs.map((m, i) => (<div key={i} style={{ display: "flex", justifyContent: m.role === "user" ? "flex-end" : "flex-start" }}><div style={{ maxWidth: "84%", padding: "10px 13px", borderRadius: 15, fontFamily: sans, fontSize: 14.5, lineHeight: 1.5, whiteSpace: "pre-wrap", background: m.role === "user" ? C.rose : C.surface, color: m.role === "user" ? "#fff" : C.ink, border: m.role === "user" ? "none" : `1px solid ${C.line}` }}>{m.content}</div></div>))}
            {busy && <div style={{ display: "flex", gap: 4, padding: "4px" }}>{[0, 1, 2].map((d) => <span key={d} style={{ width: 7, height: 7, borderRadius: 999, background: C.muted, animation: `blink 1s ${d * 0.2}s infinite` }} />)}</div>}
            {msgs.length <= 1 && <div style={{ display: "flex", flexWrap: "wrap", gap: 7 }}>{chips.map((c) => <button key={c} onClick={() => send(c)} className="btnA" style={{ background: C.roseSoft, color: C.roseDeep, border: "none", borderRadius: 999, padding: "7px 11px", fontFamily: sans, fontSize: 12.5, cursor: "pointer" }}>{c}</button>)}</div>}
            <div ref={endRef} />
          </div>
          <div style={{ padding: 12, borderTop: `1px solid ${C.line}`, background: C.surface, display: "flex", gap: 8 }}>
            <input value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => e.key === "Enter" && send()} placeholder="Ask Penny..." style={{ flex: 1, padding: "11px 14px", borderRadius: 999, border: `1.5px solid ${C.line}`, fontFamily: sans, fontSize: 14.5, color: C.ink, background: C.paper }} />
            <button onClick={() => send()} disabled={busy || !input.trim()} className="btnA" style={{ background: C.rose, color: "#fff", border: "none", borderRadius: 999, width: 44, height: 44, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", opacity: busy || !input.trim() ? 0.5 : 1, flexShrink: 0 }}><Send size={17} /></button>
          </div>
        </div>
      )}
    </>
  );
}

/* ---------------- TEAM ---------------- */
function Team({ rows, back, reload }) {
  const avg = (arr, f) => arr.length ? arr.reduce((s, r) => s + f(r), 0) / arr.length : 0;
  const withQuiz = rows.filter((r) => r.baseline && r.baseline.knowledge != null);
  const withBoth = rows.filter((r) => r.baseline && r.endline);
  const baseForMe = avg(rows.filter((r) => r.baseline), (r) => r.baseline.forMe);
  const baseConf = avg(rows.filter((r) => r.baseline), (r) => r.baseline.conf);
  const endForMe = avg(withBoth, (r) => r.endline.forMe);
  const endConf = avg(withBoth, (r) => r.endline.conf);
  const knowAvg = avg(withQuiz, (r) => r.baseline.knowledge);
  const forumTotal = rows.reduce((s, r) => s + (r.forumPosts || 0), 0);
  const pennyTotal = rows.reduce((s, r) => s + (r.pennyMsgs || 0), 0);
  const dlTotal = rows.reduce((s, r) => s + (r.downloads || 0), 0);
  const exportCsv = () => {
    const head = ["id", "base_forMe", "base_conf", "knowledge", "end_forMe", "end_conf", "forumPosts", "pennyMsgs", "downloads", "completed", "reflect_before", "reflect_after"];
    const lines = [head.join(",")];
    rows.forEach((r) => { const c = (x) => `"${String(x == null ? "" : x).replace(/"/g, '""')}"`; lines.push([c(r.id), r.baseline?.forMe ?? "", r.baseline?.conf ?? "", r.baseline?.knowledge ?? "", r.endline?.forMe ?? "", r.endline?.conf ?? "", r.forumPosts ?? 0, r.pennyMsgs ?? 0, r.downloads ?? 0, r.completed ? "yes" : "", c(r.reflection?.before ?? ""), c(r.reflection?.after ?? "")].join(",")); });
    const blob = new Blob([lines.join("\n")], { type: "text/csv" }); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = "mad_responses.csv"; a.click(); URL.revokeObjectURL(url);
  };
  const M = ({ label, value, sub }) => <div style={{ background: C.surface, boxShadow: "0 2px 12px rgba(35,33,54,.06)", borderRadius: 14, padding: 14 }}><div style={{ fontSize: 12.5, color: C.muted }}>{label}</div><div style={{ fontFamily: serif, fontSize: 23, color: C.ink, fontWeight: 700 }}>{value}</div>{sub && <div style={{ fontSize: 12, color: C.muted }}>{sub}</div>}</div>;
  return (
    <div style={{ minHeight: 440, background: C.paper, fontFamily: sans }}>
      <style>{STYLE}</style>
      <div style={{ maxWidth: 620, margin: "0 auto", padding: "0 18px 44px" }}>
        <button onClick={back} className="btnA" style={{ display: "inline-flex", alignItems: "center", gap: 6, background: "none", border: "none", color: C.muted, fontSize: 14.5, cursor: "pointer", padding: "18px 0 6px" }}><ArrowLeft size={17} /> Back</button>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}><BarChart3 size={20} color={C.teal} /><H style={{ margin: 0 }}>Results</H></div>
        <P style={{ color: C.muted, fontSize: 14.5 }}>{rows.length} visitors · {withQuiz.length} took the quiz · {withBoth.length} with before and after</P>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginTop: 6 }}>
          <M label="KR1 'is this for me'" value={`${baseForMe.toFixed(1)} → ${endForMe.toFixed(1)}`} sub={`change ${(endForMe - baseForMe >= 0 ? "+" : "") + (endForMe - baseForMe).toFixed(1)}`} />
          <M label="KR2 confidence" value={`${baseConf.toFixed(1)} → ${endConf.toFixed(1)}`} sub={`change ${(endConf - baseConf >= 0 ? "+" : "") + (endConf - baseConf).toFixed(1)}`} />
          <M label="Knowledge (avg)" value={`${knowAvg.toFixed(1)} / 5`} sub={`${withQuiz.length} quizzes`} />
          <M label="Engagement" value={`${forumTotal + pennyTotal}`} sub={`${forumTotal} forum · ${pennyTotal} Penny · ${dlTotal} downloads`} />
        </div>
        <div style={{ marginTop: 16 }}><Btn kind="teal" onClick={exportCsv}><Download size={16} /> Export CSV</Btn><span style={{ marginLeft: 10 }}><Btn kind="ghost" onClick={reload}><RefreshCw size={15} /> Refresh</Btn></span></div>
        <div style={{ fontFamily: serif, fontSize: 17, color: C.ink, margin: "22px 0 10px" }}>Reflections</div>
        <div style={{ display: "grid", gap: 8 }}>
          {rows.filter((r) => r.reflection && (r.reflection.after || "").trim()).map((r, i) => <div key={i} style={{ background: C.surface, boxShadow: "0 2px 12px rgba(35,33,54,.06)", borderRadius: 12, padding: 12, fontSize: 14, color: C.ink }}><span style={{ color: C.muted }}>Before</span> {r.reflection.before || "—"} <span style={{ color: C.muted }}>· now</span> {r.reflection.after}</div>)}
          {rows.filter((r) => r.reflection && (r.reflection.after || "").trim()).length === 0 && <P style={{ color: C.muted, fontSize: 14 }}>No reflections yet.</P>}
        </div>
      </div>
    </div>
  );
}
